INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1605, 196451, 12, 2004, '康师傅方便面惊人内幕', '提起&quot;顶新&quot;国际集团，也许还有许多人不太知道，如果说起顶益&quot;康师傅&quot;方便面，几乎家喻户晓。那&quot;好吃看得见&quot;的广告词，令多少人难忘，也使&quot;康师傅&quot;方便面的销量，在大陆占据了绝对的市场。然而，还有许多&quot;好吃看不见&quot;的东西，现公之于众，结果会使您瞠目结舌，也会令许多吃过&quot;康师傅&quot;方便面的人们如鲠在喉。 &quot;顶益&quot;公司一贯对外声称，其劳动保护和劳动环境十分好。实际上，却存在着种种 
<br>
<br>不安全隐患。
<br>
<br>一九九六年七月三十一日，酱包车间一女工在作业时，由于劳累和地面湿滑等各种原因，不慎掉到搅肉锅里被搅死，其状况简直惨不忍睹。此事震动了公司上上下下全体员工。然而，在处理这事中，工会负责人及有关大陆管理人员，却一直维护公司利益，损害自己同胞的利益，请问他们的良心何在？在解决事情的僵持阶段，死者九岁的儿子及其家属披麻带孝进厂痛哭的场景，使工人们无不潸然泪下。这泪不只是为死者，也是为了他们自己。
<br>
<br>事件发生后，公司立刻封锁消息，命令公司所有人不准向新闻界透露有关情况。调理厂物管科科长唐今尧在给其下属开会时，对工人们说：如果有谁向外界泄露了消息(主要指的是媒体)，那就让他马上回家。公司有关人员还命令，近几日内禁止任何人接近搅死人的现场，后来，搅锅只做一下简单卫生就运转了。真不知道买到吃到那个时段方便面的顾客有什幺反响。
<br>
<br>《中华人民共和国食品卫生法》第八条明确规定：食品生产经营必须符合十项卫生要求。第十一条规定：&quot;生产经营和使用食品添加剂，必须符合食品添加剂使用卫生标准和卫生管理办法的规定；不符合卫生标准和卫生管理办法的食品添加剂，不得经营、使用。&quot;象&quot;顶益&quot;公司这样有名的食品企业，在&quot;好吃看得见&quot;的背后，掩盖了多少卫生和质量问题，是不是应该查一查呢？当然，&quot;康师傅&quot;也是经常请人来检查&quot;的，在&quot;检查&quot;的同时，公关部门将安排有关人员食宿，并且是非常高的接待。一次，一个卫生检查部门来检查，调理厂内早已做好了充分的准备来&quot;接待&quot;检查人员。此刻，却出现了意外情况，生产一线需要胡萝卜粒，仓库已没有合格的了，只有一些因受潮而结块的，科长令工人用铁棍和脚粉碎进行使用。当时有位工人提出异议，这样做对吃方便面的顾客太不负责任了。而那位唐科长却厉声道：&quot;让你们怎幺干就怎幺干，否则回家。&quot;就在工人们用铁棍和脚大干特干时，几位身穿白大褂头戴小白帽的卫生检查人员走了过来，他们好象什幺也没看见什幺也没听见，谈笑风生而过。那位工人故意大喊，想引起这些人员的注意，而这些人却匆匆地走了，令人惊异。所以这样的检查，不如不查。&quot;康师傅&quot;的广告一再声称，不掺人工色素和不掺防腐剂。实际情况呢？一九九七年九月，&quot;康师傅&quot;从广东珠海一厂家，进了大约一万四千公斤虾仁（脱水），这些脱喝始乎全部喷上了红的人工色素，而检验一路过关，直至全部使用。后来仍然不断地进过这类货物。在所有&quot;康师傅&quot;的配料中，有一种所谓的&quot;营养剂&quot;，它是所有大陆籍员工不知道其真正用途的。而就是这样的&quot;营养剂&quot;，多少人想揭它的谜，却始终没有成功过。这些虽然不能证明什幺，但是，稍有常识的人们都知道，很多食品如果没有防腐剂，那产品的质量很快就会变质。走进&quot;康师傅&quot;的生产厂区，你就发现墙上贴有鲜明的标语：&quot;生产厂区，禁止拍照、摄影。 &quot;问其有关人员为什幺，答曰：商业生产秘密 。真是如此吗？调理厂，前处理车间前处理车间，是酱包生产的第一道关，葱、 姜、蒜、牛肉等等，均在这里粉碎。笔者看到，牛肉从冷库提出后，直接上了切肉机，连用水冲一下都没有。而牛肉上的污物同其它东西一起被切片，马上就到下道搅肉程序。当问到为什幺不冲洗一下时，当班组长竟说一班搅那幺多肉，冲洗得过来吗？葱、姜、蒜到是冲一下，可是 么小烂蒜并不拾出去，姜的根部还连着泥巴。甚至后面几筐发黑的蒜，也被送入搅刀中。当问道一工人时，他笑答：&quot;这还是好的呢，如果上夜班就更脏。烂葱烂蒜经常的事，送货的''康新''公司经理，据说是一位懂事长的妻弟，谁敢拒收，那他除非不想干&quot;这里看到的只是一个环节，肮脏的一切，使人难以想象得到，它就是那名声响亮的&quot;康师傅&quot;酱包调料生产的地方。一位制面厂的工人秦某讲，在面厂工作时，有一天夜班，由于劳累过度，他就暂时躺在面上休息一下，没想到竟被疯狂的老鼠撕裂了耳朵，至现在伤口还在。可见面厂的老鼠有多少。调理厂也是老鼠的&quot;天堂&quot;，上夜班的时候，成群结队的老鼠在仓库里来回飞跑游戏，它们不断穿梭于各种精料粉料之间，被这些肥肥大大的耗子们嚼过的精料粉料、葱片、胡卜粒、牛肉粒、猪肉粒、糖盐等，又被加工好装入方便面中，出售给广大顾客。&quot;AZO&quot;车间在一次投胡萝卜粒的时候，工人及时发现了一大和几只小的死老鼠，才未被投入，否则后果不堪设想。但是，据当班工人们讲，这种情况未被发现投入料中的多的是，人们闻之不禁愕然。混大料混精料车间。常人走到这里，你就会因那呛人的精料味而受不了。透过乌烟瘴气的尘埃，你就会看到那些捂得严严实实却脏兮兮看不出衣服本色的工人们，正在挥汗如雨地干活。他们的脚下到处是垃圾，一些撒在地上的精料被工人收起，再次投入锅中混料；身上各种尘物及汗水，在工人的工作中，不断地撒向和流向混料锅中。
<br>
<br>这脏兮兮的一切，怎幺能让人想起那袋装的粉料包就是&quot;康师傅&quot;粉料包呢？这是千真万确的。一位班长反映，我们的工作环境太差，身上衣服脏是没有办法的事，至于精料的质量，虽然也有检验，那不过是走马观花，一切都得依附于科长的意愿，把产量搞上去。再说，吃到顾客觜里，他们也不会感觉有多脏，多少年就这样下来了，还没有发生吃死人的事。如果认真了，可能我们早就回家了。望着工人们忙碌的身影，看着那飞扬的尘埃，想着那位班长说着的一句话：有时活忙，这混料锅几个月也不刷一次。让人联想到了什幺呢？方便面啊方便面，你吃起来可真方便，没有想到做起来也够方便的了。报纸上曾批评过&quot;康师傅&quot; 方便面的小料含菌量严重超标，但是，一些厂商及大陆个别受雇佣的管理人员，并不接受批评，不顾广大消费者的身体健康，继续大量使用不合格原料进行生产，投放市场。谈到小料含菌量超标，&quot;顶新&quot;集团的一位协理诡辩称，本公司订的菌量标准要比中国政府定得高。言外之意，并不存在超标问题，可见该公司对媒体批评的态度。&quot;顶益&quot;公司内部，有一个不成文的规定，来料不合格的，如果因急使用，可以办理&quot;特采&quot;，&quot;特采&quot;以后可以使用。而这&quot;特采&quot;的含义，只是某位台籍管理人员的一句话，不合格的马上就可以合格了。&quot;顶新&quot;集团下属有个&quot;顶芳&quot;公司，专门给&quot;顶益&quot;送蒜粉，每次四至五吨。据说&quot;顶芳&quot;公司的领导也是某位董事的亲戚，因此，每次&quot;顶芳&quot;送货，再不合格库管人员也得收，并且优先使用。每次化验结果不合格，每次都能办理成&quot;特采&quot;，没有什幺退货。如果什幺有异议，那就是自讨没趣，轻者处分重者回家。在&quot;顶益&quot;，这种违反《食品卫生法》的行为，是得到有关领导的批准和认可的。许多异常评审单都是经过领导的签字后确认的。所以一些不合格和待验品投 入使用，一些基层领导亦理直气壮。九七年年底，白糖断了料，有关部门主管却命令工人，把以前禁止使用已经结块的绵白糖，用黑脏的铁锤打碎后继续使用。&quot;康师傅&quot;只追求经济效益，不管食品卫生，对国人的健康，已经漠视到了什幺程度？这是对广大顾客的身体健康根本不负责任的。而对出口的方便面，&quot;康师傅&quot;却做到了小心再小心，惟恐洋人有什幺微词。对出口的方便面用料，公司雇佣汽车，运到天津照射中心去杀菌，全部检验合格后才能正式生产。而对销往国内的产品，他们却是从来不管不问，随心所欲，搞好&quot;公关&quot;就行了。就是这样，仍发生了俄罗斯退货事件，其原因是含菌量超标，此事被媒体曝光。
<br>
<br>后来，由于&quot;顶益&quot;公司自己成立了磨粉车间，小辣粉、姜粉及黑胡粉均由厂里来做，但含菌量太高，只好拉到天津核照射中心去杀菌。当问到核杀菌后，产品对人体有什幺影响时，有关人员支支吾吾，说不清楚。现在，据说由于照射费用太大，又不杀菌了，一批一批全部办成&quot;特采&quot;。难道出口面和内销面的不同标准，就是&quot;康师傅&quot;的国际观吗？曾有一位科长私下半　玩笑地说：&quot;中国人太多了，不值钱。&quot;难道就因为我们中国人人多，我们就可以随意被糟蹋吗？请问，谁来维护广大消费者的合法权益？一九九七年四月八日，&quot;顶益&quot;公司为了应付ISO9000认证检查，对调理厂进行了一次规模较大的扫除，在生鲜冷藏库中，工人们从各种冷冻肉上，扫出鼠粪足有一斤之多。一位科长建议，被耗子啃过的牛肉不要再用了，却被品保部孙岩处长勒令禁止。那位科长及另一位处长据理力争，却被告之再争下去对你们没有什幺好，立刻发货继续使用，在检查前必须将这批货发完，否则后果自负。最后，这批被耗子啃过的牛肉，全部被发给前处理车间，制成&quot;味美香甜&quot;的酱包料包。
<br>
<br>RP车间&quot;康师傅&quot;中华美食方便面，也许许多人都食用过，看那华丽的外包装和不菲的价格，绝对的是精品。可就是那大包的牛肉块，在RP车间夜晚存放时，大群耗子都在上面啃食过，然后再加温装袋，制成成品。有的中华美食酱包根本经不起存放，经常性不明原因地爆炸。据RP的库管讲，RP车间的所有工人均不吃RP袋装的牛肉。后来因质量问题，大批产品积压，不得不把积压产品分发给调理厂员工，但在不断有人反应下，又不发了。一九九七年十一月上旬，制面一厂一处长在巡视车间时，发现了大片尿迹在混面机旁，后仔细查看竟有尿混面现象。这位处长下令严查，没有想到后来厂里对此事不了了之。一位当班工人讲，人尿混面的事由来已久，一些素质很低的工人，不愿远路去厕所，就近撒尿已很长时间了。那为什幺厂里不追究呢？原来厂里怕事情闹出去，对厂里有影响，对方便面的销路有影响，因此就想不了了之。但纸里包不 住火，此事已在顶益闹得沸沸扬扬，无人不晓。
<br>
<br>据闻，许多已用人尿混成的面早已投放了市场。调理厂物管科精料库走进精料库，人们会发现在它码放的四十五个品种中，除酱油粉，辣椒红等七个品种是桶装的以外，其它三十多种几乎全是纸箱包装的。这些纸箱包装的精料又分进口和国产的。进口的纸箱稍整齐一点，一些国产的纸箱早已破旧不堪。特别是&quot;顶芳&quot;公司送来的蒜粉，脏破得不堪入目。走进一看，进口香料&quot;酵母精粉&quot;的纸箱上，尿液正在向下滴答，慢慢向箱内浸透，此情此景，不禁让观看者目瞪口呆；在国产香料 &quot;孜然粉&quot;的箱子上，我们看到了大片的尿迹，有些已经干透了，有些还是半湿不干的。特别是盛放精料的栈板，已全部被人尿浸泡，塑料箱中混成的精料几乎也被 &quot;照顾&quot;了。桂皮粉、黑胡粉、八角粉及海带菜等，在它们合格牌下的精料箱上均是尿迹斑斑，实在令人作呕。当问到如此卫生环境怎幺应付检查时，一位主管很爽快地答道：&quot;这有什幺，上面一给通知有检查的，一天时间就打扫干净了。&quot;那以后据说就又恢复原样了。一切都是为了对付检查，而全然不顾卫生状况如何。说到这里卫生太令人恶心时，一位工人竞笑了，说如果到原物料仓库去看看，保证你后半辈子不吃&quot;康师傅&quot;方面。原物料仓库主要存放葱片、胡萝卜粒及椰菜等等。由于这些东西比较轻，包装箱就比较大，里面还有大的塑料袋包装。而就是这些大的塑料袋，很多地方都人为地被撕口，用鼻子闻一闻，立即臭味熏人（人尿味），几乎使人站立不稳；有的地方还有人屎，竟然还拾到了用过的避孕套。
<br>
<br>这里面，人为的破坏程度比精料库有过之而无不及。就是这样，这些肮脏的精料、粉料及脱水蔬菜，正在源源不断地加工成成品，也在源源不断地投放市场。
<br>
<br>还真如那位姓刘的工人讲，这后半辈子不想再吃&quot;康师傅&quot;方便面了.', '提起"顶新"国际集团，也许还有许多人不太知道，如果说起顶益"康师傅"方便面，几乎家喻户晓。那"好吃看得见"的广告词，令多少人难忘，也使"康师傅"方便面的销量，在大陆占据了绝对的市场。然而，还有许多"好吃看不见"的东西，现公之于众，结果会使您瞠目结舌，也会令许多吃过"康师傅"方便面的人们如鲠在喉。 "顶益"公司一贯对外声称，其劳动保护和劳动环境十分好。实际上，却存在着种种

不安全隐患。

一九九六年七月三十一日，酱包车间一女工在作业时，由于劳累和地面湿滑等各种原因，不慎掉到搅肉锅里被搅死，其状况简直惨不忍睹。此事震动了公司上上下下全体员工。然而，在处理这事中，工会负责人及有关大陆管理人员，却一直维护公司利益，损害自己同胞的利益，请问他们的良心何在？在解决事情的僵持阶段，死者九岁的儿子及其家属披麻带孝进厂痛哭的场景，使工人们无不潸然泪下。这泪不只是为死者，也是为了他们自己。

事件发生后，公司立刻封锁消息，命令公司所有人不准向新闻界透露有关情况。调理厂物管科科长唐今尧在给其下属开会时，对工人们说：如果有谁向外界泄露了消息(主要指的是媒体)，那就让他马上回家。公司有关人员还命令，近几日内禁止任何人接近搅死人的现场，后来，搅锅只做一下简单卫生就运转了。真不知道买到吃到那个时段方便面的顾客有什幺反响。

《中华人民共和国食品卫生法》第八条明确规定：食品生产经营必须符合十项卫生要求。第十一条规定："生产经营和使用食品添加剂，必须符合食品添加剂使用卫生标准和卫生管理办法的规定；不符合卫生标准和卫生管理办法的食品添加剂，不得经营、使用。"象"顶益"公司这样有名的食品企业，在"好吃看得见"的背后，掩盖了多少卫生和质量问题，是不是应该查一查呢？当然，"康师傅"也是经常请人来检查"的，在"检查"的同时，公关部门将安排有关人员食宿，并且是非常高的接待。一次，一个卫生检查部门来检查，调理厂内早已做好了充分的准备来"接待"检查人员。此刻，却出现了意外情况，生产一线需要胡萝卜粒，仓库已没有合格的了，只有一些因受潮而结块的，科长令工人用铁棍和脚粉碎进行使用。当时有位工人提出异议，这样做对吃方便面的顾客太不负责任了。而那位唐科长却厉声道："让你们怎幺干就怎幺干，否则回家。"就在工人们用铁棍和脚大干特干时，几位身穿白大褂头戴小白帽的卫生检查人员走了过来，他们好象什幺也没看见什幺也没听见，谈笑风生而过。那位工人故意大喊，想引起这些人员的注意，而这些人却匆匆地走了，令人惊异。所以这样的检查，不如不查。"康师傅"的广告一再声称，不掺人工色素和不掺防腐剂。实际情况呢？一九九七年九月，"康师傅"从广东珠海一厂家，进了大约一万四千公斤虾仁（脱水），这些脱喝始乎全部喷上了红的人工色素，而检验一路过关，直至全部使用。后来仍然不断地进过这类货物。在所有"康师傅"的配料中，有一种所谓的"营养剂"，它是所有大陆籍员工不知道其真正用途的。而就是这样的"营养剂"，多少人想揭它的谜，却始终没有成功过。这些虽然不能证明什幺，但是，稍有常识的人们都知道，很多食品如果没有防腐剂，那产品的质量很快就会变质。走进"康师傅"的生产厂区，你就发现墙上贴有鲜明的标语："生产厂区，禁止拍照、摄影。 "问其有关人员为什幺，答曰：商业生产秘密 。真是如此吗？调理厂，前处理车间前处理车间，是酱包生产的第一道关，葱、 姜、蒜、牛肉等等，均在这里粉碎。笔者看到，牛肉从冷库提出后，直接上了切肉机，连用水冲一下都没有。而牛肉上的污物同其它东西一起被切片，马上就到下道搅肉程序。当问到为什幺不冲洗一下时，当班组长竟说一班搅那幺多肉，冲洗得过来吗？葱、姜、蒜到是冲一下，可是 么小烂蒜并不拾出去，姜的根部还连着泥巴。甚至后面几筐发黑的蒜，也被送入搅刀中。当问道一工人时，他笑答："这还是好的呢，如果上夜班就更脏。烂葱烂蒜经常的事，送货的''康新''公司经理，据说是一位懂事长的妻弟，谁敢拒收，那他除非不想干"这里看到的只是一个环节，肮脏的一切，使人难以想象得到，它就是那名声响亮的"康师傅"酱包调料生产的地方。一位制面厂的工人秦某讲，在面厂工作时，有一天夜班，由于劳累过度，他就暂时躺在面上休息一下，没想到竟被疯狂的老鼠撕裂了耳朵，至现在伤口还在。可见面厂的老鼠有多少。调理厂也是老鼠的"天堂"，上夜班的时候，成群结队的老鼠在仓库里来回飞跑游戏，它们不断穿梭于各种精料粉料之间，被这些肥肥大大的耗子们嚼过的精料粉料、葱片、胡卜粒、牛肉粒、猪肉粒、糖盐等，又被加工好装入方便面中，出售给广大顾客。"AZO"车间在一次投胡萝卜粒的时候，工人及时发现了一大和几只小的死老鼠，才未被投入，否则后果不堪设想。但是，据当班工人们讲，这种情况未被发现投入料中的多的是，人们闻之不禁愕然。混大料混精料车间。常人走到这里，你就会因那呛人的精料味而受不了。透过乌烟瘴气的尘埃，你就会看到那些捂得严严实实却脏兮兮看不出衣服本色的工人们，正在挥汗如雨地干活。他们的脚下到处是垃圾，一些撒在地上的精料被工人收起，再次投入锅中混料；身上各种尘物及汗水，在工人的工作中，不断地撒向和流向混料锅中。

这脏兮兮的一切，怎幺能让人想起那袋装的粉料包就是"康师傅"粉料包呢？这是千真万确的。一位班长反映，我们的工作环境太差，身上衣服脏是没有办法的事，至于精料的质量，虽然也有检验，那不过是走马观花，一切都得依附于科长的意愿，把产量搞上去。再说，吃到顾客觜里，他们也不会感觉有多脏，多少年就这样下来了，还没有发生吃死人的事。如果认真了，可能我们早就回家了。望着工人们忙碌的身影，看着那飞扬的尘埃，想着那位班长说着的一句话：有时活忙，这混料锅几个月也不刷一次。让人联想到了什幺呢？方便面啊方便面，你吃起来可真方便，没有想到做起来也够方便的了。报纸上曾批评过"康师傅" 方便面的小料含菌量严重超标，但是，一些厂商及大陆个别受雇佣的管理人员，并不接受批评，不顾广大消费者的身体健康，继续大量使用不合格原料进行生产，投放市场。谈到小料含菌量超标，"顶新"集团的一位协理诡辩称，本公司订的菌量标准要比中国政府定得高。言外之意，并不存在超标问题，可见该公司对媒体批评的态度。"顶益"公司内部，有一个不成文的规定，来料不合格的，如果因急使用，可以办理"特采"，"特采"以后可以使用。而这"特采"的含义，只是某位台籍管理人员的一句话，不合格的马上就可以合格了。"顶新"集团下属有个"顶芳"公司，专门给"顶益"送蒜粉，每次四至五吨。据说"顶芳"公司的领导也是某位董事的亲戚，因此，每次"顶芳"送货，再不合格库管人员也得收，并且优先使用。每次化验结果不合格，每次都能办理成"特采"，没有什幺退货。如果什幺有异议，那就是自讨没趣，轻者处分重者回家。在"顶益"，这种违反《食品卫生法》的行为，是得到有关领导的批准和认可的。许多异常评审单都是经过领导的签字后确认的。所以一些不合格和待验品投 入使用，一些基层领导亦理直气壮。九七年年底，白糖断了料，有关部门主管却命令工人，把以前禁止使用已经结块的绵白糖，用黑脏的铁锤打碎后继续使用。"康师傅"只追求经济效益，不管食品卫生，对国人的健康，已经漠视到了什幺程度？这是对广大顾客的身体健康根本不负责任的。而对出口的方便面，"康师傅"却做到了小心再小心，惟恐洋人有什幺微词。对出口的方便面用料，公司雇佣汽车，运到天津照射中心去杀菌，全部检验合格后才能正式生产。而对销往国内的产品，他们却是从来不管不问，随心所欲，搞好"公关"就行了。就是这样，仍发生了俄罗斯退货事件，其原因是含菌量超标，此事被媒体曝光。

后来，由于"顶益"公司自己成立了磨粉车间，小辣粉、姜粉及黑胡粉均由厂里来做，但含菌量太高，只好拉到天津核照射中心去杀菌。当问到核杀菌后，产品对人体有什幺影响时，有关人员支支吾吾，说不清楚。现在，据说由于照射费用太大，又不杀菌了，一批一批全部办成"特采"。难道出口面和内销面的不同标准，就是"康师傅"的国际观吗？曾有一位科长私下半　玩笑地说："中国人太多了，不值钱。"难道就因为我们中国人人多，我们就可以随意被糟蹋吗？请问，谁来维护广大消费者的合法权益？一九九七年四月八日，"顶益"公司为了应付ISO9000认证检查，对调理厂进行了一次规模较大的扫除，在生鲜冷藏库中，工人们从各种冷冻肉上，扫出鼠粪足有一斤之多。一位科长建议，被耗子啃过的牛肉不要再用了，却被品保部孙岩处长勒令禁止。那位科长及另一位处长据理力争，却被告之再争下去对你们没有什幺好，立刻发货继续使用，在检查前必须将这批货发完，否则后果自负。最后，这批被耗子啃过的牛肉，全部被发给前处理车间，制成"味美香甜"的酱包料包。

RP车间"康师傅"中华美食方便面，也许许多人都食用过，看那华丽的外包装和不菲的价格，绝对的是精品。可就是那大包的牛肉块，在RP车间夜晚存放时，大群耗子都在上面啃食过，然后再加温装袋，制成成品。有的中华美食酱包根本经不起存放，经常性不明原因地爆炸。据RP的库管讲，RP车间的所有工人均不吃RP袋装的牛肉。后来因质量问题，大批产品积压，不得不把积压产品分发给调理厂员工，但在不断有人反应下，又不发了。一九九七年十一月上旬，制面一厂一处长在巡视车间时，发现了大片尿迹在混面机旁，后仔细查看竟有尿混面现象。这位处长下令严查，没有想到后来厂里对此事不了了之。一位当班工人讲，人尿混面的事由来已久，一些素质很低的工人，不愿远路去厕所，就近撒尿已很长时间了。那为什幺厂里不追究呢？原来厂里怕事情闹出去，对厂里有影响，对方便面的销路有影响，因此就想不了了之。但纸里包不 住火，此事已在顶益闹得沸沸扬扬，无人不晓。

据闻，许多已用人尿混成的面早已投放了市场。调理厂物管科精料库走进精料库，人们会发现在它码放的四十五个品种中，除酱油粉，辣椒红等七个品种是桶装的以外，其它三十多种几乎全是纸箱包装的。这些纸箱包装的精料又分进口和国产的。进口的纸箱稍整齐一点，一些国产的纸箱早已破旧不堪。特别是"顶芳"公司送来的蒜粉，脏破得不堪入目。走进一看，进口香料"酵母精粉"的纸箱上，尿液正在向下滴答，慢慢向箱内浸透，此情此景，不禁让观看者目瞪口呆；在国产香料 "孜然粉"的箱子上，我们看到了大片的尿迹，有些已经干透了，有些还是半湿不干的。特别是盛放精料的栈板，已全部被人尿浸泡，塑料箱中混成的精料几乎也被 "照顾"了。桂皮粉、黑胡粉、八角粉及海带菜等，在它们合格牌下的精料箱上均是尿迹斑斑，实在令人作呕。当问到如此卫生环境怎幺应付检查时，一位主管很爽快地答道："这有什幺，上面一给通知有检查的，一天时间就打扫干净了。"那以后据说就又恢复原样了。一切都是为了对付检查，而全然不顾卫生状况如何。说到这里卫生太令人恶心时，一位工人竞笑了，说如果到原物料仓库去看看，保证你后半辈子不吃"康师傅"方面。原物料仓库主要存放葱片、胡萝卜粒及椰菜等等。由于这些东西比较轻，包装箱就比较大，里面还有大的塑料袋包装。而就是这些大的塑料袋，很多地方都人为地被撕口，用鼻子闻一闻，立即臭味熏人（人尿味），几乎使人站立不稳；有的地方还有人屎，竟然还拾到了用过的避孕套。

这里面，人为的破坏程度比精料库有过之而无不及。就是这样，这些肮脏的精料、粉料及脱水蔬菜，正在源源不断地加工成成品，也在源源不断地投放市场。

还真如那位姓刘的工人讲，这后半辈子不想再吃"康师傅"方便面了.', NULL, '2003-02-15 23:33:00', 3, '20030329000611_bbsid_196451_board_12_f537b72f41.html', '20030329000611');
